var payload = msg.payload;
if (Buffer.isBuffer(payload)) {
    payload = payload.toString();
}

payload = String(payload || '').trim();
if (!payload) {
    return null;
}

msg.TYPE = payload[0];

if (msg.TYPE == 't' || msg.TYPE == 'T') {
    var isExtended = msg.TYPE == 'T';
    var idStart = 1;
    var idLength = isExtended ? 8 : 3;
    var dlcIndex = idStart + idLength;
    var dlc = parseInt(payload[dlcIndex], 16);

    if (!Number.isFinite(dlc) || dlc > 8) {
        return null;
    }

    var dataStart = dlcIndex + 1;
    var expectedLength = dataStart + (dlc * 2);

    if (payload.length < expectedLength && !isExtended && payload[idStart + idLength] == '0') {
        // Tolerate old test frames that accidentally inserted one extra 0 after the standard ID.
        dlcIndex++;
        dlc = parseInt(payload[dlcIndex], 16);
        dataStart = dlcIndex + 1;
        expectedLength = dataStart + (dlc * 2);
    }

    if (!Number.isFinite(dlc) || dlc > 8 || payload.length < expectedLength) {
        return null;
    }

    msg.ID = payload.substr(idStart, idLength).toUpperCase();
    msg.DLC = dlc;
    msg.DATA = payload.substr(dataStart, msg.DLC * 2).toUpperCase();
    msg.BYTES = ["-", "-", "-", "-", "-", "-", "-", "-"];
    msg.TIMESTAMP = payload.substr(dataStart + msg.DLC * 2, 4);
    msg.SYSTIME = payload.substr(dataStart + msg.DLC * 2 + 4, 6);

    var position = 0;
    var byte = 0;

    while (position < (msg.DLC * 2) && byte < 8) {
        msg.BYTES[byte] = parseInt(msg.DATA.substr(position, 2), 16);
        byte++;
        position = position + 2;
    }

    var canId = parseInt(msg.ID, 16);
    msg.OBD_MODE = msg.BYTES[1];
    msg.OBD_MODE_HEX = Number.isFinite(msg.OBD_MODE)
        ? '0x' + msg.OBD_MODE.toString(16).toUpperCase().padStart(2, '0')
        : undefined;

    if (msg.OBD_MODE == 0x41) {
        msg.PID = msg.BYTES[2];
        msg.PID_HEX = '0x' + msg.PID.toString(16).toUpperCase().padStart(2, '0');
    } else if (msg.OBD_MODE == 0x43) {
        // Mode 03 response: stored Diagnostic Trouble Codes.
        msg.PID = null;
        msg.PID_HEX = 'DTC';
    } else {
        return null;
    }

    if (0x7E8 <= canId && canId <= 0x7EF) {
        return msg;
    }
}

return null;

var A = msg.BYTES[3];
var B = msg.BYTES[4];
msg.payload = Math.round(((A * 256) + B) / 4);
msg.topic = 'rpm';
return msg;

var A = msg.BYTES[3];
msg.payload = A;
msg.topic = 'speed';
return msg;

var A = msg.BYTES[3];
msg.payload = A - 40;
msg.topic = 'coolant';
return msg;

var A = msg.BYTES[3];
msg.payload = Number((A * 100 / 255).toFixed(1));
msg.topic = 'load';
return msg;

var A = msg.BYTES[3];
msg.payload = Number((A * 100 / 255).toFixed(1));
msg.topic = 'throttle';
return msg;

var A = msg.BYTES[3];
msg.payload = A - 40;
msg.topic = 'intake';
return msg;

var A = msg.BYTES[3];
var B = msg.BYTES[4];
msg.payload = Number((((A * 256) + B) / 100).toFixed(2));
msg.topic = 'maf';
return msg;

var A = msg.BYTES[3];
msg.payload = Number((A * 100 / 255).toFixed(1));
msg.topic = 'fuel';
return msg;

var A = msg.BYTES[3];
var B = msg.BYTES[4];
msg.payload = Number((((A * 256) + B) / 1000).toFixed(2));
msg.topic = 'voltage';
return msg;

var A = msg.BYTES[3];
var B = msg.BYTES[4];
msg.payload = (A * 256) + B;
msg.topic = 'mil';
return msg;

var pids = [
    "0C", "0D", "05", "04", "11", "0F", "10", "2F",
    "42", "21", "0B", "0E", "1F", "31", "46", "5C"
];
var index = context.get('index') || 0;
var pid = pids[index % pids.length];
context.set('index', index + 1);

// Standard OBD-II functional request: ID 7DF, DLC 8, data 02 01 PID 00 00 00 00 00.
msg.payload = 't7DF80201' + pid + '0000000000\r';
msg.topic = 'obd-request-' + pid;
return msg;

const A = Number(msg.BYTES[3]);
const B = Number(msg.BYTES[4]);

let field;
let value;

switch (msg.PID_HEX) {
    case "0x0C":
        field = "rpm";
        value = ((A * 256) + B) / 4;
        break;

    case "0x0D":
        field = "speed";
        value = A;
        break;

    case "0x05":
        field = "coolant";
        value = A - 40;
        break;

    case "0x04":
        field = "engine_load";
        value = A * 100 / 255;
        break;

    case "0x11":
        field = "throttle";
        value = A * 100 / 255;
        break;

    case "0x0F":
        field = "intake_temp";
        value = A - 40;
        break;

    case "0x10":
        field = "maf";
        value = ((A * 256) + B) / 100;
        break;

    case "0x2F":
        field = "fuel_level";
        value = A * 100 / 255;
        break;

    case "0x42":
        field = "module_voltage";
        value = ((A * 256) + B) / 1000;
        break;

    case "0x21":
        field = "distance_mil";
        value = (A * 256) + B;
        break;

    case "0x0B":
        field = "intake_pressure";
        value = A;
        break;

    case "0x0E":
        field = "timing_advance";
        value = A / 2 - 64;
        break;

    case "0x1F":
        field = "engine_runtime";
        value = (A * 256) + B;
        break;

    case "0x31":
        field = "distance_cleared";
        value = (A * 256) + B;
        break;

    case "0x46":
        field = "ambient_temp";
        value = A - 40;
        break;

    case "0x5C":
        field = "oil_temp";
        value = A - 40;
        break;

    default:
        return null;
}

if (!Number.isFinite(value)) {
    return null;
}

msg.topic = field;

// Object đầu là fields, object sau là tags.
msg.payload = [
    {
        [field]: Number(value.toFixed(2))
    },
    {
        vehicle_id: "vehicle-01",
        device_id: "esp32-can-01"
    }
];

return msg;

var A = msg.BYTES[3];
msg.payload = A ;
msg.topic = 'intakepressure';
return msg;

var A = msg.BYTES[3];
msg.payload = (A/2 - 64) ;
msg.topic = 'timingadvance';
return msg;

var A = msg.BYTES[3];
var B = msg.BYTES[4];
msg.payload = ((256 * A) + B) ;
msg.topic = 'runtime';
return msg;

var A = msg.BYTES[3];
var B = msg.BYTES[4];
msg.payload = ((256 * A) + B) ;
msg.topic = 'distance';
return msg;

var A = msg.BYTES[3];
msg.payload = (A - 40) ;
msg.topic = 'ambient';
return msg;

var A = msg.BYTES[3];
msg.payload = A - 40;
msg.topic = "oil_temp";
return msg;

if (msg.OBD_MODE !== 0x43) {
    return null;
}

function decodeDtc(a, b) {
    if (!Number.isFinite(a) || !Number.isFinite(b) || (a === 0 && b === 0)) {
        return null;
    }

    const systems = ['P', 'C', 'B', 'U'];
    const system = systems[(a & 0xC0) >> 6];
    const firstDigit = (a & 0x30) >> 4;
    const secondDigit = (a & 0x0F).toString(16).toUpperCase();
    const thirdDigit = ((b & 0xF0) >> 4).toString(16).toUpperCase();
    const fourthDigit = (b & 0x0F).toString(16).toUpperCase();

    return system + firstDigit + secondDigit + thirdDigit + fourthDigit;
}

const codes = [];
for (let i = 2; i + 1 < msg.BYTES.length; i += 2) {
    const code = decodeDtc(Number(msg.BYTES[i]), Number(msg.BYTES[i + 1]));
    if (code) {
        codes.push(code);
    }
}

const codeText = codes.length ? codes.join(', ') : 'NONE';

const uiMsg = {
    topic: 'dtc',
    payload: codes.length ? codeText : 'No stored DTC',
    dtc_codes: codes,
    source: msg.ID
};

const influxMsg = {
    topic: 'dtc',
    payload: [
        {
            dtc_count: codes.length,
            dtc_codes: codeText
        },
        {
            vehicle_id: 'vehicle-01',
            device_id: 'esp32-can-01',
            source_ecu: msg.ID
        }
    ]
};

return [uiMsg, influxMsg];

const codes = String(msg.payload || 'P0133')
    .split(',')
    .map(code => code.trim().toUpperCase())
    .filter(Boolean);

const codeText = codes.length ? codes.join(', ') : 'NONE';

const uiMsg = {
    topic: 'dtc',
    payload: codes.length ? codeText : 'No stored DTC',
    dtc_codes: codes,
    source: 'TEST'
};

const influxMsg = {
    topic: 'dtc',
    payload: [
        {
            dtc_count: codes.length,
            dtc_codes: codeText
        },
        {
            vehicle_id: 'vehicle-01',
            device_id: 'esp32-can-01',
            source_ecu: 'TEST'
        }
    ]
};

return [uiMsg, influxMsg];

const query = (msg.req && msg.req.query) || {};
const confirmed = String(query.confirm || '').toUpperCase() === 'YES';

msg.headers = {
    'Content-Type': 'application/json; charset=utf-8',
    'Cache-Control': 'no-store'
};

if (!confirmed) {
    msg.statusCode = 400;
    msg.payload = {
        ok: false,
        error: 'Missing confirmation. Open /clear-dtc?confirm=YES to send OBD Mode 04.',
        warning: 'Clearing DTCs can remove stored trouble codes, freeze-frame data, and readiness information.'
    };
    return [null, null, msg];
}

const command = 't7DF80204000000000000\r';
const requestedAt = new Date().toISOString();

const canMsg = {
    topic: 'clear-dtc',
    payload: command
};

const influxMsg = {
    topic: 'clear-dtc-event',
    payload: [
        {
            clear_dtc_count: 1,
            action: 'clear_dtc',
            status: 'requested'
        },
        {
            vehicle_id: 'vehicle-01',
            device_id: 'esp32-can-01',
            source: 'grafana'
        }
    ]
};

msg.statusCode = 202;
msg.payload = {
    ok: true,
    action: 'clear_dtc',
    requested_at: requestedAt,
    command: command.replace('\r', '\\r'),
    warning: 'Clear DTC command requested. Re-read DTCs after a few seconds to confirm ECU state.'
};

return [canMsg, influxMsg, msg];
